SET XACT_ABORT ON; BEGIN TRANSACTION;
CREATE TABLE EvaluationCriteria(Id INT IDENTITY PRIMARY KEY,RequirementId INT NOT NULL,Name NVARCHAR(150) NOT NULL,Description NVARCHAR(500) NULL,MaxScore DECIMAL(5,2) NOT NULL,DisplayOrder INT NOT NULL DEFAULT 0,CreatedAt DATETIME2 NOT NULL DEFAULT SYSDATETIME(),UpdatedAt DATETIME2 NULL,FOREIGN KEY(RequirementId) REFERENCES SubmissionRequirements(Id),UNIQUE(RequirementId,Name),CHECK(MaxScore>0),CHECK(DisplayOrder>=0));
CREATE TABLE Feedback(Id INT IDENTITY PRIMARY KEY,SubmissionId INT NOT NULL,GeneralComment NVARCHAR(MAX) NULL,RevisionRequired BIT NOT NULL DEFAULT 0,RevisionReason NVARCHAR(MAX) NULL,CreatedBy INT NOT NULL,CreatedAt DATETIME2 NOT NULL DEFAULT SYSDATETIME(),UpdatedAt DATETIME2 NULL,FOREIGN KEY(SubmissionId) REFERENCES Submissions(Id),FOREIGN KEY(CreatedBy) REFERENCES Users(Id),UNIQUE(SubmissionId));
CREATE TABLE Grades(Id INT IDENTITY PRIMARY KEY,SubmissionId INT NOT NULL,TotalScore DECIMAL(5,2) NOT NULL,MaxScore DECIMAL(5,2) NOT NULL DEFAULT 10,UsesCriteria BIT NOT NULL DEFAULT 0,IsPublished BIT NOT NULL DEFAULT 0,GradedBy INT NOT NULL,GradedAt DATETIME2 NOT NULL DEFAULT SYSDATETIME(),PublishedAt DATETIME2 NULL,UpdatedAt DATETIME2 NULL,FOREIGN KEY(SubmissionId) REFERENCES Submissions(Id),FOREIGN KEY(GradedBy) REFERENCES Users(Id),UNIQUE(SubmissionId),CHECK(TotalScore>=0 AND TotalScore<=MaxScore),CHECK(MaxScore>0));
CREATE TABLE CriterionScores(Id INT IDENTITY PRIMARY KEY,GradeId INT NOT NULL,CriterionId INT NOT NULL,Score DECIMAL(5,2) NOT NULL,Comment NVARCHAR(500) NULL,FOREIGN KEY(GradeId) REFERENCES Grades(Id),FOREIGN KEY(CriterionId) REFERENCES EvaluationCriteria(Id),UNIQUE(GradeId,CriterionId),CHECK(Score>=0));
CREATE TABLE SubmissionReviewHistory(Id INT IDENTITY PRIMARY KEY,SubmissionId INT NOT NULL,EventType NVARCHAR(50) NOT NULL,FromStatus NVARCHAR(30) NULL,ToStatus NVARCHAR(30) NOT NULL,Comment NVARCHAR(MAX) NULL,ActorId INT NOT NULL,CreatedAt DATETIME2 NOT NULL DEFAULT SYSDATETIME(),FOREIGN KEY(SubmissionId) REFERENCES Submissions(Id),FOREIGN KEY(ActorId) REFERENCES Users(Id));
CREATE INDEX IX_EvaluationCriteria_Requirement ON EvaluationCriteria(RequirementId,DisplayOrder);CREATE INDEX IX_CriterionScores_Grade ON CriterionScores(GradeId);CREATE INDEX IX_SubmissionReviewHistory_Submission ON SubmissionReviewHistory(SubmissionId,CreatedAt DESC);
COMMIT TRANSACTION;
